        best = 10**9
        for rx, ry in resources:
            ds = cheb(px, py, rx, ry)
            do = cheb(ox, oy, rx, ry)
            # Favor resources we reach sooner than opponent; slight preference for closeness
            val = ds - 0.35 * do
            if val < best:
                best = val
        return best

    best_move = (0, 0)
    best_score = -10**18
    # Deterministic tie-break: fixed order in dirs
    for dx, dy in dirs:
        nx, ny = sx + dx, sy + dy
        if not ok(nx, ny):
            continue
